def is_2016_claml_only(code: str) -> bool:
    return code in CLAML_VS_SCRAPED_DIFFERENCES.claml_only


def is_2016_scraped_only(code: str) -> bool:
    return code in CLAML_VS_SCRAPED_DIFFERENCES.scraped_only


def is_2016_description_difference(
    code: str,
    claml_description: str,
    scraped_description: str,
) -> bool:
    known = CLAML_VS_SCRAPED_DIFFERENCES.term_differences.get(code)
    return (
        known is not None
        and known.claml == claml_description
        and known.scraped == scraped_description
    )


def include_2016_claml_only(code: str):
    return CLAML_VS_SCRAPED_DIFFERENCES.claml_only[code].include_in_release


def include_2016_scraped_only(code: str):
    return CLAML_VS_SCRAPED_DIFFERENCES.scraped_only[code].include_in_release


def use_scraped_for_2016(code: str) -> bool:
    return CLAML_VS_SCRAPED_DIFFERENCES.term_differences.get(code).use == "scraped"


def get_2016_2019_description_difference(
    code: str,
    combined_2016_description: str,
    who_2019_description: str,
) -> ReleaseTermDifference | None:
    known = COMBINED_2016_VS_2019_DIFFERENCES.get(code)
    if (
        known is not None
        and known.combined_2016 == combined_2016_description
        and known.who_2019 == who_2019_description
    ):
        return known
    return None


def is_2016_2019_description_difference(
    code: str,
    combined_2016_description: str,
    who_2019_description: str,
) -> bool:
    return (
        get_2016_2019_description_difference(
            code,
            combined_2016_description,
            who_2019_description,
        )
        is not None
    )


def is_2016_2019_clinically_equivalent_description_difference(
    code: str,
    combined_2016_description: str,
    who_2019_description: str,
) -> bool:
    known = get_2016_2019_description_difference(
        code,
        combined_2016_description,
        who_2019_description,
    )
    return known is not None and known.clinically_equivalent


def is_2016_2019_clinically_different_description_difference(
    code: str,
    combined_2016_description: str,
    who_2019_description: str,
) -> bool:
    known = get_2016_2019_description_difference(
        code,
        combined_2016_description,
        who_2019_description,
    )
    return known is not None and not known.clinically_equivalent
